659	      const fromMode = modeForHotkey(event.key);
660	      if (fromMode) {
661	        event.preventDefault();
662	        handleModeChange(fromMode);
663	        return;
664	      }
665	      if (event.key === '?') {
666	        event.preventDefault();
667	        setCheatsheetOpen((v) => !v);
668	        return;
669	      }
670	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
671	        event.preventDefault();
672	        setPaletteOpen((v) => !v);
673	        return;
674	      }
675	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
676	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
677	        event.preventDefault();
678	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
679	        return;
680	      }
681	      // Close active tab — Ctrl/⌘+W.
682	      if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
683	        event.preventDefault();
684	        setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
685	        return;
686	      }
687	      // Undo/Redo — Ctrl/⌘+Z / Ctrl/⌘+Shift+Z.
688	      if ((event.key === 'z' || event.key === 'Z') && (event.metaKey || event.ctrlKey)) {
