706	        }
707	      }
708	    };
709	    const onKeyUp = (event: globalThis.KeyboardEvent): void => {
710	      if (!event.shiftKey) setOrthoSnapHold(false);
711	    };
712	    document.addEventListener('keydown', onKey);
713	    document.addEventListener('keyup', onKeyUp);
714	    return () => {
