130	export function countSheetViewports(elementsById: Record<string, Element>): number {
131	  let n = 0;
132	  for (const e of Object.values(elementsById)) {
133	    if (e.kind !== 'sheet') continue;
134	    const v = e.viewportsMm;
135	    n += Array.isArray(v) ? v.length : 0;
136	  }
