142	 * evidence lines in ProjectBrowser. Each entry adds a subtitle row (WP-E02/WP-X02/WP-P01).
143	 */
144	export function countSaved3dViewClipFields(elementsById: Record<string, Element>): number {
145	  let n = 0;
146	  for (const e of Object.values(elementsById)) {
147	    if (e.kind === 'viewpoint' && e.mode === 'orbit_3d') n += 1;
