152	function computeProgressiveState(
153	  value: number,
154	  warnLimit: number,
155	  overBudgetLimit: number,
156	): ProgressiveRenderingBudgetState {
157	  if (value >= overBudgetLimit) return 'over_budget';
158	  if (value >= warnLimit) return 'deferred';
159	  return 'in_budget';
160	}
