166	function sortMetricRows(rows: BrowserRenderingBudgetMetricRow[]): BrowserRenderingBudgetMetricRow[] {
167	  const stateOrder: Record<ProgressiveRenderingBudgetState, number> = {
168	    over_budget: 0,
169	    deferred: 1,
170	    stale: 2,
171	    in_budget: 3,
172	  };
173	  return [...rows].sort((a, b) => {
174	    const wa = a.status === 'warn' ? 0 : 1;
175	    const wb = b.status === 'warn' ? 0 : 1;
176	    if (wa !== wb) return wa - wb;
