189	  const priority: BrowserRenderingBudgetMetricId[] = [
190	    'plan_wire_primitives',
191	    'model_elements',
192	    'sheet_viewports',
193	    'schedule_table_rows',
194	    'saved_3d_view_clip_fields',
195	  ];
