216	function buildLargeModelProofSummary(rows: BrowserRenderingBudgetMetricRow[]): string {
217	  const anyOverBudget = rows.some((r) => r.progressiveState === 'over_budget');
218	  const anyDeferred = rows.some((r) => r.progressiveState === 'deferred');
219	  if (anyOverBudget) {
220	    const ids = rows.filter((r) => r.progressiveState === 'over_budget').map((r) => r.id).join(', ');
221	    return `Large-model proof: over_budget — metrics exceeding maximum thresholds: ${ids}.`;
222	  }
223	  if (anyDeferred) {
224	    const ids = rows.filter((r) => r.progressiveState === 'deferred').map((r) => r.id).join(', ');
