230	export function buildBrowserRenderingBudgetReadoutV1(opts: {
231	  elementsById: Record<string, Element>;
232	  planProjectionPrimitives: PlanProjectionPrimitivesV1Wire | null;
233	  scheduleHydratedRowCount: number | null;
234	  scheduleHydratedTab: string | null;
235	}): BrowserRenderingBudgetReadoutV1 {
236	  const elementCount = Object.keys(opts.elementsById).length;
237	  const wireCount = countPlanWirePrimitiveEntries(opts.planProjectionPrimitives);
238	  const viewportCount = countSheetViewports(opts.elementsById);
239	  const saved3dClipCount = countSaved3dViewClipFields(opts.elementsById);
240	
241	  const scheduleValue = opts.scheduleHydratedRowCount;
242	  const scheduleHydrated = scheduleValue !== null && scheduleValue !== undefined;
243	
244	  // Plan wire primitives
245	  const planState: ProgressiveRenderingBudgetState = !opts.planProjectionPrimitives
246	    ? 'stale'
247	    : computeProgressiveState(wireCount, BROWSER_BUDGET_WARN_PLAN_WIRE_ENTRIES, BROWSER_BUDGET_OVER_BUDGET_PLAN_WIRE_ENTRIES);
248	  const planReasonCode: ProgressiveRenderingReasonCode =
249	    planState === 'stale'
250	      ? 'plan_wire_stale_no_projection'
251	      : planState === 'over_budget'
252	        ? 'plan_wire_over_budget_very_large_primitive_count'
253	        : planState === 'deferred'
254	          ? 'plan_wire_deferred_large_primitive_count'
255	          : 'plan_wire_in_budget';
256	
257	  // Model elements
258	  const elemState = computeProgressiveState(elementCount, BROWSER_BUDGET_WARN_ELEMENT_COUNT, BROWSER_BUDGET_OVER_BUDGET_ELEMENT_COUNT);
259	  const elemReasonCode: ProgressiveRenderingReasonCode =
260	    elemState === 'over_budget'
261	      ? 'model_elements_over_budget_very_large_count'
262	      : elemState === 'deferred'
263	        ? 'model_elements_deferred_large_count'
264	        : 'model_elements_in_budget';
265	
266	  // Sheet viewports
267	  const sheetState = computeProgressiveState(viewportCount, BROWSER_BUDGET_WARN_SHEET_VIEWPORT_COUNT, BROWSER_BUDGET_OVER_BUDGET_SHEET_VIEWPORT_COUNT);
268	  const sheetReasonCode: ProgressiveRenderingReasonCode =
269	    sheetState === 'over_budget'
270	      ? 'sheet_viewports_over_budget_very_large_count'
271	      : sheetState === 'deferred'
272	        ? 'sheet_viewports_deferred_large_count'
273	        : 'sheet_viewports_in_budget';
274	
275	  // Schedule rows
276	  const schedState: ProgressiveRenderingBudgetState = !scheduleHydrated
277	    ? 'stale'
278	    : computeProgressiveState(scheduleValue as number, BROWSER_BUDGET_WARN_SCHEDULE_TABLE_ROWS, BROWSER_BUDGET_OVER_BUDGET_SCHEDULE_TABLE_ROWS);
279	  const schedReasonCode: ProgressiveRenderingReasonCode =
280	    schedState === 'stale'
281	      ? 'schedule_stale_not_hydrated'
282	      : schedState === 'over_budget'
283	        ? 'schedule_over_budget_very_large_row_count'
284	        : schedState === 'deferred'
285	          ? 'schedule_deferred_large_row_count'
286	          : 'schedule_in_budget';
287	
288	  // Saved 3D view clip fields (orbit_3d viewpoints with clip/section-box evidence in ProjectBrowser)
289	  const saved3dClipState = computeProgressiveState(saved3dClipCount, BROWSER_BUDGET_WARN_SAVED_3D_CLIP_VIEWS, BROWSER_BUDGET_OVER_BUDGET_SAVED_3D_CLIP_VIEWS);
290	  const saved3dClipReasonCode: ProgressiveRenderingReasonCode =
291	    saved3dClipState === 'over_budget'
292	      ? 'saved_3d_clip_over_budget_very_large_count'
293	      : saved3dClipState === 'deferred'
294	        ? 'saved_3d_clip_deferred_large_count'
295	        : 'saved_3d_clip_in_budget';
296	
297	  const rowsUnsorted: BrowserRenderingBudgetMetricRow[] = [
298	    {
299	      id: 'plan_wire_primitives',
300	      label: 'Plan wire primitive entries',
301	      value: opts.planProjectionPrimitives ? wireCount : null,
302	      limit: BROWSER_BUDGET_WARN_PLAN_WIRE_ENTRIES,
303	      overBudgetLimit: BROWSER_BUDGET_OVER_BUDGET_PLAN_WIRE_ENTRIES,
304	      status: progressiveStateToStatus(planState),
305	      progressiveState: planState,
306	      reasonCode: planReasonCode,
307	      ...(!opts.planProjectionPrimitives
308	        ? {
309	            detail:
310	              'No planProjectionPrimitives_v1 in client store (open a plan_view or wait for projection).',
311	          }
312	        : {}),
313	    },
314	    {
315	      id: 'model_elements',
316	      label: 'Model elements',
317	      value: elementCount,
318	      limit: BROWSER_BUDGET_WARN_ELEMENT_COUNT,
319	      overBudgetLimit: BROWSER_BUDGET_OVER_BUDGET_ELEMENT_COUNT,
320	      status: progressiveStateToStatus(elemState),
321	      progressiveState: elemState,
322	      reasonCode: elemReasonCode,
323	    },
324	    {
325	      id: 'sheet_viewports',
326	      label: 'Sheet viewports (placed)',
327	      value: viewportCount,
328	      limit: BROWSER_BUDGET_WARN_SHEET_VIEWPORT_COUNT,
329	      overBudgetLimit: BROWSER_BUDGET_OVER_BUDGET_SHEET_VIEWPORT_COUNT,
330	      status: progressiveStateToStatus(sheetState),
331	      progressiveState: sheetState,
332	      reasonCode: sheetReasonCode,
333	    },
334	    {
335	      id: 'schedule_table_rows',
336	      label: 'Schedules · active tab rows',
337	      value: scheduleHydrated ? scheduleValue : null,
338	      limit: BROWSER_BUDGET_WARN_SCHEDULE_TABLE_ROWS,
339	      overBudgetLimit: BROWSER_BUDGET_OVER_BUDGET_SCHEDULE_TABLE_ROWS,
340	      status: progressiveStateToStatus(schedState),
341	      progressiveState: schedState,
342	      reasonCode: schedReasonCode,
343	      detail: !scheduleHydrated
344	        ? 'Not hydrated (Schedules panel idle, loading, or no model).'
345	        : opts.scheduleHydratedTab
346	          ? `tab=${opts.scheduleHydratedTab}`
347	          : undefined,
348	    },
349	    {
350	      id: 'saved_3d_view_clip_fields',
351	      label: 'Saved 3D views · clip/section-box evidence rows',
352	      value: saved3dClipCount,
353	      limit: BROWSER_BUDGET_WARN_SAVED_3D_CLIP_VIEWS,
354	      overBudgetLimit: BROWSER_BUDGET_OVER_BUDGET_SAVED_3D_CLIP_VIEWS,
355	      status: progressiveStateToStatus(saved3dClipState),
356	      progressiveState: saved3dClipState,
357	      reasonCode: saved3dClipReasonCode,
358	    },
359	  ];
360	
361	  const rows = sortMetricRows(rowsUnsorted);
362	  return {
363	    format: 'browserRenderingBudgetReadout_v1',
364	    rows,
365	    suggestedInvestigationRoute: pickSuggestedRoute(rowsUnsorted),
366	    largeModelProofSummary: buildLargeModelProofSummary(rowsUnsorted),
367	  };
368	}
369	
370	/** Monospace lines for Agent Review / inspector surfaces. */
371	export function formatBrowserRenderingBudgetLines(readout: BrowserRenderingBudgetReadoutV1): string[] {
372	  const lines: string[] = [];
373	  lines.push('browserRenderingBudgetReadout_v1');
374	  for (const r of readout.rows) {
375	    const val = r.value === null ? '—' : String(r.value);
376	    lines.push(
377	      `${r.progressiveState} ${r.id} ${val}/${r.limit}/${r.overBudgetLimit} [${r.reasonCode}]${r.detail ? ` · ${r.detail}` : ''}`,
378	    );
379	  }
380	  lines.push(`large_model_proof: ${readout.largeModelProofSummary}`);
381	  lines.push(`route: ${readout.suggestedInvestigationRoute}`);
382	  return lines;
383	}
